<style>
  .pi{
color:#1a1d1f;
font-family:"Helvetica Neue",Arial,sans-serif;
font-size:11.5px;
line-height:1.45;
border:2px solid #0f4c5c;
padding:14px;
}
  .pi *{ box-sizing:border-box; }
  .pi table{ width:100%; border-collapse:collapse; }
  .pi .muted{ color:#6b7378; }
  .pi .accent{ color:#0f4c5c; }
  .pi .right{ text-align:right; }
  .pi .center{ text-align:center; }
  .pi .lbl{ font-size:8.5px; letter-spacing:.09em; text-transform:uppercase; color:#8a9096; font-weight:700; }
  .pi .val{ font-size:11.5px; color:#1a1d1f; }
  .pi .strong{ font-weight:700; }

  /* Header */
  .pi .head{
border:2px solid #0f4c5c;
border-bottom:3px solid #0f4c5c;
margin-bottom:12px;
}
  .pi .co-name{ font-size:21px; font-weight:800; color:#0f4c5c; letter-spacing:.02em; line-height:1.1; }
  .pi .co-tag{ font-size:9px; font-style:italic; color:#5f7d86; margin-top:2px; letter-spacing:.04em; }
  .pi .co-meta{ font-size:9.5px; color:#5a6167; margin-top:6px; }
  .pi .stamp{ text-align:right; }
  .pi .stamp .title{ font-size:15px; font-weight:800; letter-spacing:.14em; color:#0f4c5c; }
  .pi .pill{ display:inline-block; font-size:8px; letter-spacing:.1em; font-weight:700; text-transform:uppercase;
             padding:2px 8px; border-radius:10px; margin-top:6px;
             -webkit-print-color-adjust:exact; print-color-adjust:exact; }
  .pi .pill.ok{ background:#e6f2ee; color:#12694e; }
  .pi .pill.pending{ background:#fdeecd; color:#8a5b00; }
  .pi .stamp .no{ font-size:12.5px; font-weight:800; color:#1a1d1f; margin-top:8px; }
  .pi .stamp .dt{ font-size:9.5px; color:#6b7378; }

  /* Party cards */
  .pi .cards{ margin-top:14px; }
  .pi .card{
border:2px solid #0f4c5c;
border-radius:4px;
padding:10px;
vertical-align:top;
}
  .pi .card .who{ font-size:12px; font-weight:700; color:#1a1d1f; margin:1px 0 3px; }
  .pi .card .addr{ font-size:10px; color:#4b5257; white-space:pre-line; }
  .pi .card .gst{ font-size:9.5px; margin-top:5px; }
  .pi .gap{ width:12px; }

  /* Reference strip */
  .pi .refs{
margin-top:12px;
border:2px solid #0f4c5c;
border-collapse:collapse;
}
  .pi .refs td{
border:1px solid #888;
padding:8px;
width:25%;
}
  .pi .chip{ display:inline-block; font-size:8.5px; font-weight:700; letter-spacing:.05em; padding:1px 7px;
             border-radius:9px; border:1px solid #cfd6da; color:#5a6167; margin-right:4px; }
  .pi .chip.on{ background:#0f4c5c; color:#fff; border-color:#0f4c5c;
                -webkit-print-color-adjust:exact; print-color-adjust:exact; }

  /* Items */
  .pi .items{
margin-top:16px;
border:2px solid #0f4c5c;
border-collapse:collapse;
}
  .pi .items thead th{ background:#0f4c5c; color:#fff; font-size:9px; letter-spacing:.06em; text-transform:uppercase;
                       font-weight:700; padding:8px 9px; text-align:left;
                       -webkit-print-color-adjust:exact; print-color-adjust:exact; }
  .pi .items tbody td{
padding:8px 9px;
border:1px solid #999;
vertical-align:top;
font-size:10.5px;
}
  .pi .items tbody tr:nth-child(even) td{ background:#f7f9fa; -webkit-print-color-adjust:exact; print-color-adjust:exact; }
  .pi .items .sl{ width:4%; color:#8a9096; }
  .pi .items .desc{ width:46%; }
  .pi .items .desc .name{ font-weight:700; color:#1a1d1f; }
  .pi .items .desc .sub{ color:#6b7378; font-size:9.5px; white-space:pre-line; }
  .pi .items .num{ width:16%; text-align:right; white-space:nowrap; }
  .pi .items .per{ width:8%; text-align:center; color:#6b7378; }
  .pi .items .qty{ width:10%; text-align:right; }

  /* Totals + words */
  .pi .foot-split{ margin-top:14px; }
  .pi .words{ vertical-align:top; padding-right:18px; }
  .pi .words .lbl{ margin-bottom:3px; }
  .pi .words .amt-words{ font-size:11px; font-style:italic; color:#2b3135; }
  .pi .warranty-box{ margin-top:12px; font-size:10px; }
  .pi .tot{
width:46%;
vertical-align:top;
border:2px solid #0f4c5c;
}
  .pi .tot table td{ padding:6px 12px; font-size:11px; }
  .pi .tot .row td{ border-bottom:1px solid #eef1f2; }
  .pi .tot .row .k{ color:#5a6167; }
  .pi .tot .row .v{ text-align:right; font-weight:600; }
  .pi .tot .grand td{ border-top:2px solid #0f4c5c; font-weight:800; font-size:12px; color:#1a1d1f; }
  .pi .tot .bal td{ background:#0f4c5c; color:#fff; font-weight:800; font-size:12.5px;
                    -webkit-print-color-adjust:exact; print-color-adjust:exact; }
  .pi .tot .bal .k{ letter-spacing:.05em; }

  /* Footer */
  .pi .pay-terms{
margin-top:14px;
border:2px solid #0f4c5c;
padding:10px;
background:#f5f8f9;
font-size:10px;
}
  .pi .bankrow{
margin-top:18px;
border:2px solid #0f4c5c;
}
  .pi .bank td{ vertical-align:top; }
  .pi .bank .lbl{ margin-bottom:5px; }
  .pi .bank .line{ font-size:10px; padding:1px 0; }
  .pi .bank .line b{ color:#1a1d1f; }
  .pi .sign{ text-align:right; vertical-align:bottom; }
  .pi .sign .for{ font-size:10px; font-weight:700; color:#1a1d1f; }
  .pi .sign .space{ height:42px; }
  .pi .sign .auth{ font-size:9.5px; color:#6b7378; border-top:1px solid #b9c1c6; display:inline-block; padding-top:3px; min-width:150px; }
  .pi .branches{
margin-top:16px;
padding:8px;
border:2px solid #0f4c5c;
text-align:center;
font-size:8.5px;
color:#8a9096;
}
  .pi .branches .web{ color:#0f4c5c; font-weight:700; }
  .pi .ctrl{
padding:6px;
border:2px solid #0f4c5c;
border-top:none;
text-align:center;
font-size:7.5px;
color:#aeb5ba;
}
</style>

<div class="pi">

    <table class="head">
    <tr>
      <td style="width:62%; vertical-align:top;">
        <div class="co-name">ENERTECH UPS PVT. LTD.</div>
        <div class="co-tag">Answering All Power Needs</div>
        <div class="co-meta">
