          Ph. 020 22923172 / 20291172 &nbsp;&bull;&nbsp; finance@enertechups.com<br>
          <span class="strong">GSTIN</span> 27AAACE6766A1ZT &nbsp;&bull;&nbsp; <span class="strong">PAN</span> AAACE6766A
        </div>
      </td>
                                                                </tr>
  </table>

    <table class="cards">
    <tr>
      <td class="card" style="width:49%;">
