        <div class="who">{{ doc.customer_name or "" }}</div>
        <div class="addr">{{ doc.consignee_address or "" }}</div>
        {%- if doc.consignee_gstin %}<div class="gst"><span class="strong">GSTIN</span> {{ doc.consignee_gstin }}</div>{%- endif %}
      </td>
      <td class="gap"></td>
      <td class="card" style="width:49%;">
        <div class="lbl accent">Buyer{{ " (same as consignee)" if doc.buyer_same_as_consignee else "" }}</div>
        {%- if doc.buyer_same_as_consignee %}
          <div class="who">{{ doc.customer_name or "" }}</div>
          <div class="addr">{{ doc.consignee_address or "" }}</div>
          {%- if doc.consignee_gstin %}<div class="gst"><span class="strong">GSTIN</span> {{ doc.consignee_gstin }}</div>{%- endif %}
        {%- else %}
          <div class="who">{{ doc.buyer_name or "" }}</div>
          <div class="addr">{{ doc.address or "" }}</div>
          {%- if doc.buyer_gstin %}<div class="gst"><span class="strong">GSTIN</span> {{ doc.buyer_gstin }}</div>{%- endif %}
        {%- endif %}
      </td>
    </tr>
  </table>

    <table class="refs">
    <tr>
      <td>
        <div class="lbl">Buyer's Order No.</div>
        <div class="val">{{ doc.buyers_order_no or "—" }}</div>
      </td>
      <td>
        <div class="lbl">Order Date</div>
        <div class="val">{{ frappe.utils.formatdate(doc.buyers_order_date, "dd-MM-yyyy") if doc.buyers_order_date else "—" }}</div>
      </td>
      <td>
        <div class="lbl">Order Received Via</div>
        <div class="val">
          <span class="chip {{ 'on' if doc.by_po }}">PO</span>
          <span class="chip {{ 'on' if doc.by_verbal }}">Verbal</span>
          <span class="chip {{ 'on' if doc.by_email }}">Email</span>
        </div>
      </td>
      <td>
        <div class="lbl">Supplier's Ref</div>
        <div class="val">{{ doc.suppliers_ref or "—" }}</div>
      </td>
    </tr>
    <tr>
      <td>
        <div class="lbl">Delivery Note</div>
        <div class="val">{{ doc.delivery_note or "—" }}</div>
      </td>
      <td>
        <div class="lbl">Delivery Date</div>
        <div class="val">{{ frappe.utils.formatdate(doc.delivery_date, "dd-MM-yyyy") if doc.delivery_date else "—" }}</div>
      </td>
      <td>
        <div class="lbl">Dispatched Through</div>
        <div class="val">{{ doc.dispatched_through or "—" }}</div>
      </td>
      <td>
        <div class="lbl">Freight Terms</div>
        <div class="val">{{ doc.freight_terms or "—" }}</div>
      </td>
    </tr>
    {%- if doc.other_references %}
    <tr>
      <td colspan="4">
        <div class="lbl">Other Reference(s)</div>
        <div class="val">{{ doc.other_references }}</div>
      </td>
    </tr>
    {%- endif %}
  </table>

    <table class="items">
    <thead>
      <tr>
        <th class="sl">#</th>
        <th class="desc">Description of Goods</th>
        <th class="qty" style="text-align:right;">Qty</th>
        <th class="num" style="text-align:right;">Rate</th>
        <th class="per" style="text-align:center;">Per</th>
        <th class="num" style="text-align:right;">Amount</th>
      </tr>
    </thead>
    <tbody>
      {%- for row in doc.items %}
      <tr>
        <td class="sl">{{ loop.index }}</td>
        <td class="desc">
          <div class="name">{{ row.get('item_code') or row.get('item_name') or '' }}</div>
          <div class="sub">{{ row.get('description') or '' }}</div>
        </td>
        <td class="qty">{{ "{:g}".format(row.get('qty') or 0) }}</td>
        <td class="num">{{ money(row.get('rate')) }}</td>
        <td class="per">{{ row.get('uom') or '' }}</td>
        <td class="num">{{ money(row.get('amount')) }}</td>
      </tr>
      {%- endfor %}
    </tbody>
  </table>

    <table class="foot-split">
    <tr>
      <td class="words">
        <div class="lbl">Amount in Words</div>
        <div class="amt-words">{{ frappe.utils.money_in_words(doc.total or 0) }}</div>

        {%- if doc.warranty %}
        <div class="warranty-box"><span class="lbl">Warranty</span><br>{{ doc.warranty }}</div>
        {%- endif %}
      </td>
      <td class="tot">
        <table>
          <tr class="row">
            <td class="k">Sub Total</td>
            <td class="v">{{ money(subtotal) }}</td>
          </tr>
          {%- if tax > 0.5 %}
          <tr class="row">
            <td class="k">GST / Taxes</td>
            <td class="v">{{ money(tax) }}</td>
          </tr>
          {%- endif %}
          <tr class="grand">
            <td class="k">Total</td>
            <td class="v">{{ money(doc.total) }}</td>
          </tr>
          {%- if doc.advance_payment %}
          <tr class="row">
            <td class="k">Advance Payment</td>
            <td class="v">{{ money(doc.advance_payment) }}</td>
          </tr>
          {%- endif %}
          <tr class="bal">
            <td class="k">Balance Payment</td>
            <td class="v">{{ money(doc.balance_payment) }}</td>
          </tr>
        </table>
      </td>
    </tr>
  </table>

    {%- if doc.modeterms_of_payment %}
  <div class="pay-terms"><span class="lbl">Mode / Terms of Payment</span> &nbsp; {{ doc.modeterms_of_payment }}</div>
  {%- endif %}

    <table class="bankrow">
