{{ frappe.utils.fmt_money(v or 0, currency="INR") }}
{%- endmacro -%}

{%- set subtotal = (doc.items | sum(attribute="amount")) or 0 -%}
{%- set cgst_total = (doc.items | sum(attribute="custom_cgst_amount")) or 0 -%}
{%- set sgst_total = (doc.items | sum(attribute="custom_sgst_amount")) or 0 -%}
