{%- set amount_in_words = frappe.utils.money_in_words(grand_total, "INR") -%}

<style>

@page{
    size:A4;
    /* Footer is now a real <tfoot> that repeats inside the table flow on every
       page, so we no longer need a huge reserved bottom margin for it.
       A small uniform margin is enough. */
    margin:8mm 8mm 8mm 8mm;
}

html,body{
    margin:0;
    padding:0;
    background:#fff;
    font-family:Arial,Helvetica,sans-serif;
    color:#222;
    font-size:10px;
}

*{
    box-sizing:border-box;
}

/* ---------- PER-PAGE FIXED BORDER FRAME ---------- */
/* This is safe to keep as position:fixed because it's purely decorative
   (a thin outline) and never needs to reserve layout space. */
.page-border{
    position:fixed;
    top:0mm;
    left:0mm;
    right:0mm;
    bottom:0mm;
    border:2px solid #1c3f60;
    pointer-events:none;
    z-index:1000;
}

/* ---------- REPEATING FOOTER (real tfoot, NOT position:fixed) ----------
   Because this lives inside <tfoot> with display:table-footer-group,
   the rendering engine repeats it at the bottom of every page AND
   reserves real vertical space for it before laying out tbody content.
   That means content can never render "behind" it — there's nothing to
   overlap, it's part of normal flow. */
.page-frame{
    width:100%;
    border-collapse:collapse;
}

.page-frame > thead{
    display:table-header-group;
}

.page-frame > tfoot{
    display:table-footer-group;
}

.footer-repeat td{
    padding:0;
    border-top:2px solid #1c3f60;
    background:#fff;
}

.invoice{
    width:100%;
}

table{
    width:100%;
    border-collapse:collapse;
}

td,th{
    vertical-align:top;
}

.header{
    border-bottom:2px solid #1c3f60;
}

.header td{
    padding:6px 12px;
}

.company-legal-name{
    font-size:13px;
    font-weight:bold;
    color:#11466a;
    letter-spacing:.5px;
    text-align:center;
    text-transform:uppercase;
    margin-bottom:2px;
}

.company-address{
    line-height:1.3;
    font-size:9px;
    text-align:center;
}

.invoice-meta-divider{
    border:none;
    border-top:1px solid #1c3f60;
    margin:0;
}

.invoice-meta-table{
    width:100%;
    border-collapse:collapse;
}

.invoice-meta-table td{
    padding:4px 10px;
    font-size:9px;
    font-weight:500;
    vertical-align:top;
    border-right:1px solid #c9d6e0;
}

.invoice-meta-table td:last-child{
    border-right:none;
}

.invoice-meta-table .meta-row{
    margin-bottom:2px;
}

.invoice-meta-table .meta-row:last-child{
    margin-bottom:0;
}

.header-block{
    border-bottom:2px solid #1c3f60;
}

.items{
    margin-top:6px;
}

.items thead{
    display:table-header-group;
}

.items tr{
    page-break-inside:avoid;
    break-inside:avoid;
}

.items th{
    background:#11466a;
    color:white;
    border:1px solid #777;
    padding:4px;
    font-size:9px;
}

.items td{
    border:1px solid #999;
    padding:4px;
    font-size:9px;
    line-height:1.25;
}

.items tbody tr:nth-child(even){
    background:#fafafa;
}

.sl{ width:4%; }
.desc{ width:32%; word-break:break-word; white-space:normal; }
.qty{ width:6%; text-align:right; white-space:nowrap; }
.rate{ width:9%; text-align:right; white-space:nowrap; }
.uom{ width:6%; text-align:center; }
.gstcol{ width:9%; text-align:right; }
.amount{ width:10%; text-align:right; white-space:nowrap; }

.summary{
    page-break-inside:avoid;
    break-inside:avoid;
}

.words-box{
    border:2px solid #1c3f60;
    height:100%;
}

.words-box-title{
    background:#11466a;
    color:#fff;
    padding:4px;
    font-size:9px;
    font-weight:bold;
    text-transform:uppercase;
}

.words-box-content{
    padding:6px 8px;
    font-size:9px;
    font-weight:bold;
    line-height:1.4;
    text-transform:capitalize;
}

/* ---------- SUMMARY (Sub Total / GST / Total) TABLE ----------
   Every row now uses the SAME font-size and padding. Only the grand
   total row is bold + a very slightly tinted background — no size jump. */
.totals-table{
    width:100%;
    border-collapse:collapse;
    border-spacing:0;
    border:2px solid #1c3f60;
    table-layout:fixed;
}

.totals-table td{
    margin:0;
    padding:4px 6px;
    border:none;
    border-bottom:1px solid #ccc;
    border-radius:0 !important;
    box-shadow:none !important;
    -webkit-box-shadow:none !important;
    background-clip:padding-box;
    font-size:9px;
    line-height:1.3;
}

.totals-table tr:last-child td{
    border-bottom:none;
}

.totals-table td.label{
    width:55%;
    font-weight:bold;
}

.totals-table td.value{
    width:45%;
    text-align:right;
}

.totals-table tr.grand-total td{
    font-weight:bold;
    background:#eef6fb;
}

.bank-section{
    page-break-inside:avoid;
    break-inside:avoid;
}

/* Locks summary + bank details as ONE unbreakable unit so they always
   move to the next page together instead of splitting */
.summary-bank-lock{
    page-break-inside:avoid;
    break-inside:avoid;
}

</style>

