css:
/* --- 1. Page Setup & Global Styles --- */
@page {
    margin-top: 4cm;
    margin-bottom: 3.5cm;
    margin-left: 1.5cm;
    margin-right: 1.5cm;
}

.print-format-wrapper {
    font-family: Arial, Helvetica, sans-serif;
    font-size: 12px;
    line-height: 1.5;
    color: #333;
}

.print-format-wrapper ul,
.print-format-wrapper ol {
    padding-left: 20px;
}

.text-center { text-align: center; }
.text-right { text-align: right; }

.section-title {
    font-size: 16px;
    font-weight: bold;
    margin-top: 30px;
    margin-bottom: 15px;
    border-bottom: 2px solid #333;
    padding-bottom: 5px;
}

/* --- 2. Header & Recipient Section --- */
.recipient-section {
    display: flex;
    justify-content: space-between;
    margin-bottom: 20px;
}
.document-details {
    text-align: right;
}
.recipient-address {
    margin-top: 15px;
}
.subject-line {
    margin-top: 20px;
    margin-bottom: 20px;
    border-top: 1px solid #ddd;
    border-bottom: 1px solid #ddd;
    padding: 10px 0;
}

/* --- 3. Introduction & Manufacturing Sections --- */
.intro-content {
    margin-bottom: 20px;
}
.intro-content b {
    display: inline-block;
    margin-top: 15px;
}
.manufacturing-section {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-top: 20px;
    margin-bottom: 20px;
}
.manufacturing-text { width: 58%; }
.manufacturing-image { width: 40%; }
.manufacturing-image img { border: 1px solid #ddd; padding: 2px; }

/* --- 4. Commercial Offer Item Table --- */
.custom-quotation-table table { width: 100%; border-collapse: collapse; font-size: 11px; }
.custom-quotation-table th, .custom-quotation-table td { border: 1px solid #000; padding: 8px; vertical-align: top; }
.custom-quotation-table th { background-color: #e9ecef; text-align: center; font-weight: bold; }
.item-data-row td { border-bottom: none; }
.tax-details-row td { border-top: none; border-bottom: 2px solid #000; padding: 5px 8px; border-left: none; border-right: none; }
.tax-details-row td:first-child { border-left: 1px solid #000; }
.tax-details-row td:last-child { border-right: 1px solid #000; }
.tax-amount-box { border: 1px solid #000; padding: 4px; display: inline-block; background-color: #f8f9fa; min-width: 90px; }
.tax-label { padding-right: 15px !important; }
.no-tax-border { padding: 0 !important; height: 0; border-bottom: 2px solid #000 !important; }

/* --- 5. Totals Summary Section --- */
.summary-section {
    display: flex;
    justify-content: space-between;
    margin-top: 20px;
    page-break-inside: avoid;
}
.summary-left { width: 60%; }
.summary-right { width: 35%; }
.totals-table { width: 100%; border-collapse: collapse; }
.totals-table td { padding: 8px; border: 1px solid #ccc; }
.totals-table .grand-total td { background-color: #e9ecef; font-size: 14px; }

/* --- 6. Terms & Conditions Section --- */
.terms-container {
    margin-top: 30px;
    page-break-before: auto; /* Avoids breaking unless necessary */
}
.terms-container h3, .terms-container h4 {
    font-size: 14px;
    font-weight: bold;
    margin-top: 20px;
    margin-bottom: 10px;
    border-bottom: 1px solid #d1d8dd;
    padding-bottom: 5px;
}
.terms-container > ol > li {
    display: flex;
    align-items: flex-start;
    margin-bottom: 10px;
}
.terms-container > ol > li > strong {
    flex-shrink: 0;
    width: 180px;
    margin-right: 10px;
}
.terms-container .sub-list { padding-left: 20px; margin-top: 5px; width: 100%; }
.bank-details p { margin: 0; }
.bank-details strong { display: inline-block; width: 90px; }

/* --- 7. Closing & Signature Section --- */
.closing-and-signature-section {
    margin-top: 30px;
    page-break-inside: avoid;
}
.signature-space {
    height: 60px; /* Provides space for a manual signature */
}

.print-format th {
    background-color: transparent !important;
    border-bottom: 1px solid !important;
    border-top: none !important;
}
.print-format .ql-editor {
    padding-left: 0px;
    padding-right: 0px;
}

.print-format table {
    margin-bottom: 0px;
    }
.print-format .table-data tr:last-child { 
    border-bottom: 1px solid !important;
}

.print-format .table-inner tr:last-child {
    border-bottom:none !important;
}
.print-format .table-inner {
    margin: 0px 0px;
}

.print-format .table-data ul li { 
    color:#787878 !important;
}

.no-top-border {
    border-top:none !important;
}

.table-inner td {
    padding-left: 0px !important;    
    padding-top: 1px !important;
    padding-bottom: 1px !important;
    color:#787878 !important;
}

.total {
    background-color: lightgrey !important;
    padding-top: 4px !important;
    padding-bottom: 4px !important;
}

