{%- set subtotal = (doc.items | sum(attribute="amount")) or 0 -%}

<style>

@page{
    size:A4;
    /* Footer is now a real <tfoot> that repeats inside the table flow on every
       page, so we no longer need a big reserved bottom margin for it. */
    margin:8mm 8mm 8mm 8mm;
}

html,body{
    margin:0;
    padding:0;
    background:#fff;
    font-family:Arial,Helvetica,sans-serif;
    color:#222;
    font-size:11px;
}

*{
    box-sizing:border-box;
}

/* ---------- PER-PAGE FIXED BORDER FRAME (replaces .invoice border) ---------- */
/* Safe to keep position:fixed — purely decorative, never reserves layout space. */
.page-border{
    position:fixed;
    top:0mm;
    left:0mm;
    right:0mm;
    bottom:0mm;
    border:2px solid #1c3f60;
    pointer-events:none;
    z-index:1000;
}

/* ---------- REPEATING FOOTER (real tfoot, NOT position:fixed) ----------
   Lives inside <tfoot> with display:table-footer-group, so it repeats at
   the bottom of every page as part of normal table flow and reserves real
   space for itself before the rest of the content is laid out. Content can
   never render behind it because there's nothing to overlap. */
.page-frame{
    width:100%;
    border-collapse:collapse;
}

.page-frame > thead{
    display:table-header-group;
}

.page-frame > tfoot{
    display:table-footer-group;
}

.footer-repeat td{
    padding:0;
    border-top:2px solid #1c3f60;
    background:#fff;
}

.invoice{
    width:100%;
}

table{
    width:100%;
    border-collapse:collapse;
}

td,th{
    vertical-align:top;
}

.header{
    border-bottom:2px solid #1c3f60;
}

.header td{
    padding:12px;
}

.company-name{
    font-size:20px;
    font-weight:bold;
    color:#11466a;
    letter-spacing:.5px;
    text-align:center;
}

.company-address{
    margin-top:8px;
    line-height:1.6;
    font-size:10px;
    text-align:center;
}

.section-title{
    font-size:12px;
    font-weight:bold;
    color:#11466a;
    margin-bottom:8px;
    text-transform:uppercase;
}

.items{
    margin-top:15px;
}

.items thead{
    display:table-header-group;
}

.items tr{
    page-break-inside:avoid;
    break-inside:avoid;
}

.items th{
    background:#11466a;
    color:white;
    border:1px solid #777;
    padding:8px;
    font-size:10px;
}

.items td{
    border:1px solid #999;
    padding:8px;
    font-size:10px;
}

.items tbody tr:nth-child(even){
    background:#fafafa;
}

.summary{
    page-break-inside:avoid;
    break-inside:avoid;
}

/* ---------- TOTALS TABLE (Total Qty / Sub Total / Grand Total) ----------
   Same reset as the Proforma Invoice fix: kill inherited border-radius /
   box-shadow from Frappe's site CSS so label cells don't overflow the
   outer border, and keep every row the same font-size/padding. */
.totals-table{
    width:100%;
    border-collapse:collapse;
    border-spacing:0;
    border:2px solid #1c3f60;
    table-layout:fixed;
}

.totals-table td{
    margin:0;
    padding:6px;
    border:none;
    border-bottom:1px solid #ccc;
    border-radius:0 !important;
    box-shadow:none !important;
    -webkit-box-shadow:none !important;
    background-clip:padding-box;
    font-size:9px;
    line-height:1.3;
}

.totals-table tr:last-child td{
    border-bottom:none;
}

.totals-table td.label{
    width:60%;
    font-weight:bold;
